import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const n="/kb/assets/01-domain-hierarchy.gq_9ngph.png",l="/kb/assets/02-recursive-authoritative.ut1uRJaO.png",d="/kb/assets/03-ttl-cache-timer.CuMKXOw8.png",h="/kb/assets/04-internal-dns-service-name.6ZMZ-ulI.png",C=JSON.parse('{"title":"第 3 讲｜域名和 DNS","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/03-域名和DNS.md","filePath":"00.互联网与架构基础/03-域名和DNS.md","lastUpdated":null}'),p={name:"00.互联网与架构基础/03-域名和DNS.md"};function o(r,s,c,k,g,F){return i(),t("div",null,[...s[0]||(s[0]=[e('<h1 id="第-3-讲-域名和-dns" tabindex="-1">第 3 讲｜域名和 DNS <a class="header-anchor" href="#第-3-讲-域名和-dns" aria-label="Permalink to &quot;第 3 讲｜域名和 DNS&quot;">​</a></h1><p>IP 地址(尤其是 IPv4 的 <code>203.0.113.10</code>、IPv6 的 <code>2001:db8::8a2e:370:7334</code>)不便于人类记忆。<strong>域名</strong>是为了让用户可以用易记的名称(如 <code>www.example.com</code>)访问服务而设计的中间层。但机器之间通信仍然使用 IP——浏览器拿到域名后,需要查询该名称对应的 IP,这一过程称为 <strong>DNS(Domain Name System)解析</strong>。</p><p>DNS 不只用于公网网站。公司内部平台、云 VPC 内的服务、Kubernetes 里的 Service,背后都是同一套域名解析机制。本讲先讲清楚域名的结构、DNS 的查询过程、记录类型、TTL 的作用,然后展开内网 DNS 的应用场景和常见解析异常的判定。</p><h2 id="一、域名的层级结构" tabindex="-1">一、域名的层级结构 <a class="header-anchor" href="#一、域名的层级结构" aria-label="Permalink to &quot;一、域名的层级结构&quot;">​</a></h2><p>域名按层级组织,<strong>从右往左层级越来越细</strong>。以 <code>www.example.com</code> 为例:</p><p><img src="'+n+'" alt="域名从根到主机名的层级结构"></p><table tabindex="0"><thead><tr><th>段</th><th>层级</th><th>管理者</th></tr></thead><tbody><tr><td><code>com</code></td><td>顶级域(TLD)</td><td>ICANN 等国际机构</td></tr><tr><td><code>example.com</code></td><td>主域名(Second-level Domain)</td><td>域名注册者(公司/个人)</td></tr><tr><td><code>www</code></td><td>子域名(Sub-domain)</td><td>主域名所有者自行控制</td></tr></tbody></table><p>顶级域分两类:</p><ul><li><strong>通用顶级域</strong>(gTLD):<code>.com</code>、<code>.org</code>、<code>.net</code>、<code>.io</code>、<code>.app</code></li><li><strong>国家代码顶级域</strong>(ccTLD):<code>.cn</code>、<code>.jp</code>、<code>.uk</code>、<code>.de</code></li></ul><p>主域名所有者可以在自己的主域名下创建任意子域名,<strong>按业务用途拆分</strong>。常见的拆分方式:</p><table tabindex="0"><thead><tr><th>子域名</th><th>用途</th></tr></thead><tbody><tr><td><code>www</code></td><td>官网</td></tr><tr><td><code>api</code></td><td>后端 API</td></tr><tr><td><code>static</code> / <code>cdn</code></td><td>静态资源/CDN</td></tr><tr><td><code>m</code></td><td>移动版网站</td></tr><tr><td><code>admin</code></td><td>管理后台(应限制内网或 VPN 访问)</td></tr><tr><td><code>mail</code></td><td>邮件服务</td></tr><tr><td><code>grafana</code> / <code>prometheus</code></td><td>监控平台</td></tr><tr><td><code>harbor</code> / <code>nexus</code></td><td>镜像/制品仓库</td></tr></tbody></table><p>看到一个陌生的域名时,从子域名前缀通常能大致判断指向的服务类型,这对快速理解故障范围有帮助。</p><h2 id="二、递归-dns-与权威-dns" tabindex="-1">二、递归 DNS 与权威 DNS <a class="header-anchor" href="#二、递归-dns-与权威-dns" aria-label="Permalink to &quot;二、递归 DNS 与权威 DNS&quot;">​</a></h2><p>DNS 系统有两类核心角色:</p><h3 id="权威-dns" tabindex="-1">权威 DNS <a class="header-anchor" href="#权威-dns" aria-label="Permalink to &quot;权威 DNS&quot;">​</a></h3><p><strong>最终保存域名解析记录、对外回答&quot;该域名对应什么&quot;的服务器</strong>。每个主域名都有自己的权威 DNS。在云厂商控制台或域名注册商管理后台配置的解析记录,就是写入权威 DNS。</p><ul><li>阿里云解析、腾讯云 DNS、AWS Route53、Cloudflare 都属于权威 DNS 服务商</li><li>改解析记录,本质是改权威 DNS 上的配置</li></ul><h3 id="递归-dns" tabindex="-1">递归 DNS <a class="header-anchor" href="#递归-dns" aria-label="Permalink to &quot;递归 DNS&quot;">​</a></h3><p><strong>替客户端完成完整查询过程的中间服务器</strong>。客户端不会自己从根 DNS 开始一路查到底——递归 DNS 帮你完成这件事并返回最终结果。</p><ul><li>系统配置中 <code>/etc/resolv.conf</code> 里的 <code>nameserver</code>,通常就是递归 DNS</li><li><code>8.8.8.8</code>(Google)、<code>1.1.1.1</code>(Cloudflare)、<code>114.114.114.114</code>(国内通用)、运营商 DNS、公司内网 DNS,都属于递归 DNS</li></ul><h3 id="完整查询过程" tabindex="-1">完整查询过程 <a class="header-anchor" href="#完整查询过程" aria-label="Permalink to &quot;完整查询过程&quot;">​</a></h3><p><img src="'+l+`" alt="递归 DNS 负责跑腿，权威 DNS 负责给最终答案"></p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20autonumber%0A%20%20participant%20Client%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20participant%20Recursor%20as%20%E9%80%92%E5%BD%92%20DNS%0A%20%20participant%20Root%20as%20%E6%A0%B9%20DNS%0A%20%20participant%20TLD%20as%20%E9%A1%B6%E7%BA%A7%E5%9F%9F%20DNS%0A%20%20participant%20Auth%20as%20%E6%9D%83%E5%A8%81%20DNS%0A%0A%20%20Client-%3E%3ERecursor%3A%20%E6%9F%A5%E8%AF%A2%20www.example.com%0A%20%20Recursor-%3E%3ERoot%3A%20.com%20%E7%9A%84%20DNS%20%E5%9C%A8%E5%93%AA%E9%87%8C%0A%20%20Root--%3E%3ERecursor%3A%20%E8%BF%94%E5%9B%9E%20.com%20%E7%9A%84%20DNS%20%E5%9C%B0%E5%9D%80%0A%20%20Recursor-%3E%3ETLD%3A%20example.com%20%E7%9A%84%20DNS%20%E5%9C%A8%E5%93%AA%E9%87%8C%0A%20%20TLD--%3E%3ERecursor%3A%20%E8%BF%94%E5%9B%9E%20example.com%20%E7%9A%84%E6%9D%83%E5%A8%81%20DNS%0A%20%20Recursor-%3E%3EAuth%3A%20www.example.com%20%E7%9A%84%20A%20%E8%AE%B0%E5%BD%95%E6%98%AF%E4%BB%80%E4%B9%88%0A%20%20Auth--%3E%3ERecursor%3A%20%E8%BF%94%E5%9B%9E%20A%20%2F%20CNAME%20%E8%AE%B0%E5%BD%95%0A%20%20Recursor--%3E%3EClient%3A%20%E8%BF%94%E5%9B%9E%E6%9C%80%E7%BB%88%E7%BB%93%E6%9E%9C%0A"></div><h3 id="权威-dns-与递归-dns-的分工对运维的影响" tabindex="-1">权威 DNS 与递归 DNS 的分工对运维的影响 <a class="header-anchor" href="#权威-dns-与递归-dns-的分工对运维的影响" aria-label="Permalink to &quot;权威 DNS 与递归 DNS 的分工对运维的影响&quot;">​</a></h3><ul><li><strong>修改解析记录</strong> — 在权威 DNS(控制台)操作,通常立即生效</li><li><strong>生效全网范围</strong> — 不取决于权威 DNS,而取决于<strong>各级递归 DNS 的缓存何时过期</strong>——这正是 TTL 的作用,下一节展开</li></ul><h2 id="三、dns-记录类型" tabindex="-1">三、DNS 记录类型 <a class="header-anchor" href="#三、dns-记录类型" aria-label="Permalink to &quot;三、DNS 记录类型&quot;">​</a></h2><p>DNS 不只能返回 IP,还有多种记录类型对应不同的解析需求:</p><table tabindex="0"><thead><tr><th>类型</th><th>含义</th><th>典型用途</th></tr></thead><tbody><tr><td><code>A</code></td><td>IPv4 地址</td><td>大多数业务域名</td></tr><tr><td><code>AAAA</code></td><td>IPv6 地址</td><td>IPv6 网络</td></tr><tr><td><code>CNAME</code></td><td>别名,指向另一个域名</td><td>接入 CDN、域名跳转</td></tr><tr><td><code>MX</code></td><td>邮件服务器域名</td><td>邮件投递</td></tr><tr><td><code>TXT</code></td><td>任意文本</td><td>域名所有权验证、SPF/DKIM 反垃圾邮件、ACME 证书申请</td></tr><tr><td><code>NS</code></td><td>该域名的权威 DNS 服务器</td><td>子域委派</td></tr><tr><td><code>SOA</code></td><td>域起始授权</td><td>域的元数据,自动生成</td></tr><tr><td><code>SRV</code></td><td>服务记录</td><td>指定服务的主机名+端口,LDAP/SIP 等场景</td></tr></tbody></table><p>业务方日常接触最多的是 <code>A</code>、<code>AAAA</code>、<code>CNAME</code> 三种。</p><h3 id="cdn-接入场景下的-cname-链" tabindex="-1">CDN 接入场景下的 CNAME 链 <a class="header-anchor" href="#cdn-接入场景下的-cname-链" aria-label="Permalink to &quot;CDN 接入场景下的 CNAME 链&quot;">​</a></h3><p>接入 CDN 的业务域名几乎都使用 CNAME 而非 A 记录。原因:</p><ul><li>CDN 厂商的边缘节点 IP <strong>动态分配</strong>,根据用户位置就近返回</li><li>业务方无法预测 IP、不可能写死</li></ul><p>典型解析链:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询: www.example.com</span></span>
<span class="line"><span>权威 DNS: CNAME → example.com.cdn-provider.net</span></span>
<span class="line"><span>查询: example.com.cdn-provider.net</span></span>
<span class="line"><span>CDN 权威 DNS: A → 北京用户得到 203.0.113.42,上海用户得到 198.51.100.13</span></span></code></pre></div><p><code>dig</code> 工具可以完整看到这条链路:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ANSWER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SECTION:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">www.example.com.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        300</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  IN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  CNAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  example.com.cdn-provider.net.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">example.com.cdn-provider.net.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> IN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   203.0.113.42</span></span></code></pre></div><h3 id="cname-的限制" tabindex="-1">CNAME 的限制 <a class="header-anchor" href="#cname-的限制" aria-label="Permalink to &quot;CNAME 的限制&quot;">​</a></h3><p><strong>主域名(zone apex)不能配 CNAME</strong>——<code>example.com</code> 本身只能配 A,不能 CNAME 到其他域名。这是 RFC 规定,部分场景下需要主域名也走 CDN,但又不允许 CNAME,云厂商提供了 ALIAS 或 ANAME 记录作为变通方案(在 DNS 层做隐式 CNAME 解析)。</p><h2 id="四、ttl-与缓存" tabindex="-1">四、TTL 与缓存 <a class="header-anchor" href="#四、ttl-与缓存" aria-label="Permalink to &quot;四、TTL 与缓存&quot;">​</a></h2><p>DNS 查询结果会在多个层级被缓存:浏览器、操作系统、路由器、运营商 DNS、上游 DNS。<strong>TTL(Time To Live)就是告诉这些缓存&quot;这条记录可以保留多久&quot;</strong>——单位是秒。</p><p><img src="`+d+`" alt="TTL 决定 DNS 缓存多久过期"></p><p>例如 <code>TTL = 300</code>,意味着查询到这条记录后,300 秒内的重复查询使用缓存,300 秒后必须重新查询。</p><h3 id="ttl-长短的取舍" tabindex="-1">TTL 长短的取舍 <a class="header-anchor" href="#ttl-长短的取舍" aria-label="Permalink to &quot;TTL 长短的取舍&quot;">​</a></h3><table tabindex="0"><thead><tr><th>TTL 范围</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>长(3600s ~ 86400s)</td><td>查询少,权威 DNS 负载低</td><td>切换 IP 时缓存等待时间长</td></tr><tr><td>短(60s ~ 300s)</td><td>切换快,几分钟全网生效</td><td>查询量大,权威 DNS 压力大</td></tr></tbody></table><p>业务正常运行期间,TTL 可以配置稍长(3600s 即 1 小时)以减少查询压力。</p><h3 id="ip-切换前的标准操作-提前调低-ttl" tabindex="-1">IP 切换前的标准操作:提前调低 TTL <a class="header-anchor" href="#ip-切换前的标准操作-提前调低-ttl" aria-label="Permalink to &quot;IP 切换前的标准操作:提前调低 TTL&quot;">​</a></h3><p>域名迁移或主备切换前的标准操作:</p><ol><li><strong>提前 1-2 天</strong>把 TTL 调低(例如从 3600 改为 60-300 秒)</li><li><strong>等待原 TTL 完全过期</strong>(各级缓存都已使用新 TTL)</li><li><strong>执行 A 记录的 IP 切换</strong></li><li><strong>观察 1-2 天</strong>确认稳定后,把 TTL 恢复正常值</li></ol><p>这个流程的关键价值:<strong>新 IP 出问题时,回滚的等待时间从数小时缩短到几分钟</strong>。</p><h3 id="缓存清理" tabindex="-1">缓存清理 <a class="header-anchor" href="#缓存清理" aria-label="Permalink to &quot;缓存清理&quot;">​</a></h3><p>修改解析记录后,某些位置仍解析到旧 IP,通常是缓存未过期。手动清理本地缓存:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux (systemd-resolved)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemd-resolve</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --flush-caches</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolvectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flush-caches</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux (nscd)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nscd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dscacheutil</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -flushcache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> killall</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -HUP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mDNSResponder</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ipconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /flushdns</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 浏览器:大多数浏览器需要重启或访问 chrome://net-internals/#dns</span></span></code></pre></div><p>上游递归 DNS 的缓存无法用客户端命令清理,只能<strong>等待 TTL 自然过期</strong>——这正是 TTL 决定全网生效时间的体现。</p><h2 id="五、内网-dns" tabindex="-1">五、内网 DNS <a class="header-anchor" href="#五、内网-dns" aria-label="Permalink to &quot;五、内网 DNS&quot;">​</a></h2><p>DNS 在内网场景中的应用范围远超公网。公司内部、云 VPC、Kubernetes 集群内都广泛使用 DNS。</p><p><img src="`+h+`" alt="内网 DNS 用服务名解耦后端 IP"></p><h3 id="内网-dns-的典型场景" tabindex="-1">内网 DNS 的典型场景 <a class="header-anchor" href="#内网-dns-的典型场景" aria-label="Permalink to &quot;内网 DNS 的典型场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>域名示例</th></tr></thead><tbody><tr><td>公司内部 GitLab</td><td><code>gitlab.company.local</code></td></tr><tr><td>云 VPC 内的 MySQL</td><td><code>mysql.internal.example.com</code></td></tr><tr><td>K8s Service</td><td><code>api.default.svc.cluster.local</code></td></tr><tr><td>K8s Pod</td><td><code>pod-name.namespace.pod.cluster.local</code></td></tr></tbody></table><h3 id="内网-dns-的核心价值-解耦-ip-与服务" tabindex="-1">内网 DNS 的核心价值:解耦 IP 与服务 <a class="header-anchor" href="#内网-dns-的核心价值-解耦-ip-与服务" aria-label="Permalink to &quot;内网 DNS 的核心价值:解耦 IP 与服务&quot;">​</a></h3><p>服务的 IP 在生产环境中频繁变化:</p><ul><li>数据库主备切换 → IP 切换</li><li>Kubernetes Pod 重建 → IP 变化</li><li>应用扩缩容 → 新增/减少 IP</li></ul><p><strong>通过 DNS 解耦后,业务代码使用稳定的域名访问,IP 变化对应用透明</strong>。Kubernetes 是这种解耦最彻底的实现——一个 Service 名背后的 Pod IP 可能一天变几次,应用始终用同一个域名,完全无感知。</p><h3 id="kubernetes-内的-dns-解析机制" tabindex="-1">Kubernetes 内的 DNS 解析机制 <a class="header-anchor" href="#kubernetes-内的-dns-解析机制" aria-label="Permalink to &quot;Kubernetes 内的 DNS 解析机制&quot;">​</a></h3><p>K8s 集群内的 DNS 由 CoreDNS 提供,服务名按固定格式构成:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;service-name&gt;.&lt;namespace&gt;.svc.cluster.local</span></span></code></pre></div><p>例如 <code>default</code> namespace 下的 <code>api</code> Service,完整域名是 <code>api.default.svc.cluster.local</code>。同 namespace 内的 Pod 可以省略部分,直接用 <code>api</code>(由 search domain 自动补全)。</p><h3 id="内网-dns-故障的判定" tabindex="-1">内网 DNS 故障的判定 <a class="header-anchor" href="#内网-dns-故障的判定" aria-label="Permalink to &quot;内网 DNS 故障的判定&quot;">​</a></h3><p>应用日志中出现:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lookup api.default.svc.cluster.local: no such host</span></span></code></pre></div><p>判定路径:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Service 是否存在</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Service 的 Endpoints 是否有 Pod</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> endpoints</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. CoreDNS 是否正常</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kube-system</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> k8s-app=kube-dns</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kube-system</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> k8s-app=kube-dns</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tail=50</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 从有问题的 Pod 内部直接 DNS 查询</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">po</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nslookup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.default.svc.cluster.local</span></span></code></pre></div><p>具体的网络 DNS 故障类型与处理方式,在 <a href="/kb/01.Linux基础/14-网络诊断与排错">第 14 讲 网络诊断与排错</a> 的 DNS 章节展开。</p><h2 id="六、dns-解析异常的判定信号" tabindex="-1">六、DNS 解析异常的判定信号 <a class="header-anchor" href="#六、dns-解析异常的判定信号" aria-label="Permalink to &quot;六、DNS 解析异常的判定信号&quot;">​</a></h2><p>DNS 出问题时通常表现为以下几种结果:</p><table tabindex="0"><thead><tr><th>结果</th><th>含义</th><th>大概率原因</th></tr></thead><tbody><tr><td><code>NXDOMAIN</code></td><td>域名不存在</td><td>域名拼写错误、记录未配置、域名已过期</td></tr><tr><td><code>SERVFAIL</code></td><td>DNS 服务器内部错误</td><td>上游权威 DNS 故障、网络断、DNSSEC 校验失败</td></tr><tr><td><code>REFUSED</code></td><td>DNS 服务器拒绝回答</td><td>防火墙拦截、DNS 服务器配置限制查询来源</td></tr><tr><td>解析到旧 IP</td><td>缓存未过期</td><td>TTL 还有效或本机 hosts 写死</td></tr><tr><td>不同地区解析到不同 IP</td><td>智能调度</td><td>CDN、GeoDNS、运营商缓存差异</td></tr></tbody></table><h3 id="nxdomain-不一定是故障" tabindex="-1">NXDOMAIN 不一定是故障 <a class="header-anchor" href="#nxdomain-不一定是故障" aria-label="Permalink to &quot;NXDOMAIN 不一定是故障&quot;">​</a></h3><p>某些应用启动时会探测多个候选域名(例如 DNS search 自动补全后的多个 FQDN),部分候选返回 NXDOMAIN 是正常的。日志中出现少量 NXDOMAIN 不必紧张,<strong>真正需要警觉的是</strong>:</p><ul><li>业务核心域名出现 NXDOMAIN</li><li>多个域名同时 SERVFAIL</li><li>解析耗时从毫秒级突然升到秒级</li></ul><p>后两种情况通常意味着 DNS 链路本身出了问题,排查方向是上游 DNS 服务器、网络连通性、CoreDNS 健康状态。</p><h3 id="dns-解析慢的判定" tabindex="-1">DNS 解析慢的判定 <a class="header-anchor" href="#dns-解析慢的判定" aria-label="Permalink to &quot;DNS 解析慢的判定&quot;">​</a></h3><p>应用偶尔出现&quot;启动后第一次请求慢几秒,后续正常&quot;,大概率是 DNS 解析慢:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dig @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">本机配置的 DNS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> example.com</span></span></code></pre></div><p>正常本地 DNS 响应应当在 100ms 以内。如果接近 1 秒甚至几秒,说明本地或上游 DNS 性能有问题。处理方式:</p><ul><li>在本机部署 dnsmasq / systemd-resolved / unbound 做本地缓存,避免每次都查上游</li><li>应用层启用 DNS 缓存(JVM 的 <code>networkaddress.cache.ttl</code>、Python 的 socket 缓存)</li><li>检查 <code>/etc/resolv.conf</code> 中的 <code>options</code> 参数:<code>timeout</code> 默认 5 秒过长,可调到 1-2 秒;<code>attempts</code> 默认 2 次过多,可调到 1</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/resolv.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">options</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> timeout:2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attempts:1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rotate</span></span></code></pre></div><p><code>rotate</code> 让多个 nameserver 轮询使用,避免第一个 DNS 慢时所有查询都先等它超时。</p><h2 id="七、查-dns-的常用工具" tabindex="-1">七、查 DNS 的常用工具 <a class="header-anchor" href="#七、查-dns-的常用工具" aria-label="Permalink to &quot;七、查 DNS 的常用工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>用途</th></tr></thead><tbody><tr><td><code>dig</code></td><td>直接查权威 DNS,显示完整结果(推荐)</td></tr><tr><td><code>nslookup</code></td><td>简化的查询工具,输出较简略</td></tr><tr><td><code>host</code></td><td>进一步简化的工具</td></tr><tr><td><code>getent hosts</code></td><td>走系统 NSS,模拟应用的真实解析路径</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 标准查询</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 指定 DNS 服务器查询</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @8.8.8.8</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @1.1.1.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查特定记录类型</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> A</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MX</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TXT</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从根域名开始递归追踪</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +trace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反向解析(IP → 域名)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只输出最终 IP(脚本化)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 走系统 NSS(包括 /etc/hosts),模拟应用看到的解析</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hosts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span></code></pre></div><h3 id="dig-与-getent-hosts-必须对比看" tabindex="-1"><code>dig</code> 与 <code>getent hosts</code> 必须对比看 <a class="header-anchor" href="#dig-与-getent-hosts-必须对比看" aria-label="Permalink to &quot;\`dig\` 与 \`getent hosts\` 必须对比看&quot;">​</a></h3><p>应用看到的解析结果走的是系统 NSS(<code>nsswitch.conf</code> 中通常是 <code>files dns</code>,先查 <code>/etc/hosts</code> 再查 DNS),<code>dig</code> 直接绕过 hosts 查 DNS。<strong>两者结果不一致时,几乎都是 <code>/etc/hosts</code> 写死了旧记录</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 修改的是 DNS,但应用一直访问旧 IP——常见根因是 /etc/hosts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/hosts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/nsswitch.conf</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ^hosts</span></span></code></pre></div><p>判定流程:<code>dig</code> 出来对、<code>getent hosts</code> 出来不对 → 几乎一定是 hosts 或 NSS 顺序问题。这是 DNS 排查中最常见的认知陷阱。</p>`,93)])])}const D=a(p,[["render",o]]);export{C as __pageData,D as default};
